const raw = $json || {};
const telegramMsg = raw.message || raw.edited_message || raw.channel_post || raw.edited_channel_post || null;

// --- OPTION B: DÉCODAGE DU MULTIPART ---
let payload = raw.body || telegramMsg || raw;
if (payload && typeof payload.payload === 'string') {
    try { payload = JSON.parse(payload.payload); } catch(e) {}
}
// ---------------------------------------

const isTelegram = Boolean(raw.update_id || raw.message_id || raw.message?.message_id || telegramMsg?.message_id);

const now = new Date();
const rand = Math.random().toString(36).slice(2, 6).toUpperCase();
const providedIngestionId = typeof payload.ingestion_id === 'string' ? payload.ingestion_id.trim() : '';
const ingestion_id = providedIngestionId || ('SIGA-ING-' + now.getUTCFullYear() + String(now.getUTCMonth()+1).padStart(2,'0') + String(now.getUTCDate()).padStart(2,'0') + '-' + String(now.getUTCHours()).padStart(2,'0') + String(now.getUTCMinutes()).padStart(2,'0') + String(now.getUTCSeconds()).padStart(2,'0') + '-' + String(now.getUTCMilliseconds()).padStart(3,'0') + '-' + rand);

// --- SÉCURITÉ : SECRET EN DUR ---
const configuredSecret = 'TON_SECRET_ICI';
// --------------------------------

const headerSecret = raw.headers?.['x-siga-shared-secret'] || raw.headers?.['X-SIGA-SHARED-SECRET'] || null;
const authHeader = raw.headers?.authorization || raw.headers?.Authorization || null;
const bearerToken = typeof authHeader === 'string' ? authHeader.replace(/^Bearer\s+/i, '').trim() : '';
const authConfigured = !isTelegram && !!configuredSecret;
const authPassed = isTelegram || !authConfigured || headerSecret === configuredSecret || bearerToken === configuredSecret;

const binaryData = $input.first()?.binary || $binary || {};
const binaryKeys = Object.keys(binaryData);

const extOf = (name) => {
  const s = String(name || '');
  const m = s.match(/\.([A-Za-z0-9]+)$/);
  return m ? m[1].toLowerCase() : '';
};

const isImageBinary = (key, bin) => {
  const mime = String(bin?.mimeType || '').toLowerCase();
  const fileName = String(bin?.fileName || bin?.filename || '');
  const ext = extOf(fileName);
  return /^image\//.test(mime) || /^image_upload\d+$/i.test(key) || /^photo(_\d+)?$/i.test(key) || /^media_\d+$/i.test(key) || ['jpg','jpeg','png','webp','gif','bmp','tif','tiff'].includes(ext);
};

const isDocumentBinary = (key, bin) => {
  if (isImageBinary(key, bin)) return false;
  const mime = String(bin?.mimeType || '').toLowerCase();
  const fileName = String(bin?.fileName || bin?.filename || '');
  const ext = extOf(fileName);
  return mime === 'application/pdf'
    || mime.startsWith('application/')
    || ['pdf','doc','docx','xls','xlsx','csv','txt','rtf'].includes(ext);
};

const sortByNumericSuffix = (a, b) => {
  const na = parseInt(String(a).replace(/\D+/g, ''), 10);
  const nb = parseInt(String(b).replace(/\D+/g, ''), 10);
  if (Number.isFinite(na) && Number.isFinite(nb) && na !== nb) return na - nb;
  return String(a).localeCompare(String(b));
};

const imageKeys = binaryKeys.filter(k => isImageBinary(k, binaryData[k])).sort(sortByNumericSuffix);
const documentKeys = binaryKeys.filter(k => isDocumentBinary(k, binaryData[k])).sort(sortByNumericSuffix);

const normalizedImages = imageKeys.map((key, idx) => {
  const bin = binaryData[key] || {};
  return {
    index: idx + 1,
    filename: bin.fileName || bin.filename || ('image_' + (idx + 1) + '.jpg'),
    mime_type: bin.mimeType || 'image/jpeg',
    content_base64: bin.data || null,
    binary_key: key
  };
});

const normalizedDocuments = documentKeys.map((key, idx) => {
  const bin = binaryData[key] || {};
  return {
    index: idx + 1,
    filename: bin.fileName || bin.filename || ('document_' + (idx + 1)),
    mime_type: bin.mimeType || 'application/octet-stream',
    content_base64: bin.data || null,
    binary_key: key,
    source_field: key
  };
});

const legacyImages = normalizedImages.length === 0 && Array.isArray(payload.images)
  ? payload.images.map((img, idx) => ({
      index: Number(img.index || idx + 1),
      filename: img.filename || ('image_' + (idx + 1) + '.jpg'),
      mime_type: img.mime_type || 'image/jpeg',
      content_base64: img.content_base64 || null,
      binary_key: img.binary_key || null
    }))
  : [];

const legacyDocuments = normalizedDocuments.length === 0 && Array.isArray(payload.documents)
  ? payload.documents.map((doc, idx) => ({
      index: Number(doc.index || idx + 1),
      filename: doc.filename || ('document_' + (idx + 1)),
      mime_type: doc.mime_type || 'application/octet-stream',
      content_base64: doc.content_base64 || null,
      binary_key: doc.binary_key || null,
      source_field: doc.source_field || null
    }))
  : [];

const images = normalizedImages.length > 0 ? normalizedImages : legacyImages;
const documents = normalizedDocuments.length > 0 ? normalizedDocuments : legacyDocuments;
const validImageCount = images.filter(img => !!img.content_base64 || !!img.binary_key).length;
const validDocumentCount = documents.filter(doc => !!doc.content_base64 || !!doc.binary_key).length;

const errors = [];
if (images.length === 0 && documents.length === 0) errors.push({ code: 'no_media', message: 'At least one image or document is required' });
if (!authPassed) errors.push({ code: 'unauthorized', message: 'Invalid shared secret' });

let messageText = '';
if (typeof payload.message === 'string') {
  messageText = payload.message;
} else {
  messageText = payload.message?.text || payload.message_text || payload.text || payload.caption || telegramMsg?.caption || telegramMsg?.text || '';
}

const tgFrom = telegramMsg?.from || {};
const sender = isTelegram
  ? {
      id: tgFrom.id || null,
      display_name: [tgFrom.first_name, tgFrom.last_name].filter(Boolean).join(' ').trim() || tgFrom.username || null
    }
  : (payload.sender || {});

const source = isTelegram ? 'telegram' : (payload.source || (imageKeys.length > 0 || documentKeys.length > 0 ? 'mobile_app' : 'whatsapp'));

const inputBinary = $input.first()?.binary || {};

return [{
  binary: Object.keys(inputBinary).length > 0 ? inputBinary : undefined,
  json: {
    ok: errors.length === 0,
    stage: errors.length === 0 ? 'accepted' : 'rejected',
    error: errors.length ? errors[0].message : null,
    errors,
    auth: {
      configured: authConfigured,
      passed: authPassed,
      mode: isTelegram ? 'telegram_trigger' : (authConfigured ? 'server_secret_enforced' : 'open_unconfigured'),
      accepted_via: isTelegram ? 'telegram_trigger' : (!authConfigured ? 'open_unconfigured' : (headerSecret === configuredSecret ? 'x-siga-shared-secret' : (bearerToken === configuredSecret ? 'authorization_bearer' : 'rejected'))),
      secret_source: isTelegram ? 'telegram' : (authConfigured ? 'server_env' : 'not_configured')
    },
    project: payload.project || 'SIGA',
    entity_type: payload.entity_type || 'equipment',
    source,
    ingestion_id,
    sender: { id: sender.id || null, display_name: sender.display_name || null },
    message: {
      id: payload.message_id || payload.message?.id || telegramMsg?.message_id || null,
      text: messageText,
      received_at: payload.message?.received_at || (telegramMsg?.date ? new Date(telegramMsg.date * 1000).toISOString() : now.toISOString())
    },
    images,
    documents,
    image_count: images.length,
    valid_image_count: validImageCount,
    document_count: documents.length,
    valid_document_count: validDocumentCount,
    context: isTelegram ? {
      telegram: {
        update_id: raw.update_id || null,
        chat: telegramMsg?.chat || null,
        document: telegramMsg?.document || null,
        photo_count: Array.isArray(telegramMsg?.photo) ? telegramMsg.photo.length : 0,
        caption: telegramMsg?.caption || null
      }
    } : (payload.context || {}),
    raw_payload: raw
  }
}];

