const text = ($json.message?.text || '').trim();
const lower = text.toLowerCase();
const result = {
  location_hint: '',
  ownership_mode: '',
  purchase_price: null,
  purchase_currency: 'EUR',
  acquisition_note: '',
  usage_notes: '',
  accessories: []
};
const locationPatterns = [
  /(?:stock[ée]?|rang[ée]?|situ[ée]?|actuellement)[^.,;:]*?(?:au|à|dans|sur|sous|derrière|devant|au dessus de|au-dessus de)\s+([^.,;]+)/i,
  /(au dessus de l[’']établi|au-dessus de l[’']établi|sur l[’']établi|dans l[’']atelier|dans le garage)/i
];
for (const re of locationPatterns) {
  const m = text.match(re);
  if (m) {
    result.location_hint = (m[1] || '').trim();
    break;
  }
}
if (/(?:donné|donnée|donne|offert|offerte|gratuit|gratuite|récupéré|recupere)/i.test(lower)) result.ownership_mode = 'given';
else if (/(?:prêt|pret|emprunt)/i.test(lower)) result.ownership_mode = 'loan';
else if (/(?:acheté|achetee|payé|payee|facture|facturé|facturee)/i.test(lower)) result.ownership_mode = 'purchased';
const priceMatch = text.match(/(\d+[.,]?\d*)\s?(€|eur|euros)/i);
if (priceMatch) {
  result.purchase_price = Number(priceMatch[1].replace(',', '.'));
  result.purchase_currency = 'EUR';
}
if (/je ne l'ai pas payé|je ne l'ai pas payee|il m'a été donné|il m'a ete donne|objet reçu gratuitement|objet recu gratuitement/i.test(lower)) {
  result.ownership_mode = 'given';
  result.purchase_price = 0;
  result.purchase_currency = 'EUR';
  result.acquisition_note = 'Objet reçu gratuitement / donné';
}
const accessories = [];
if (/batterie/i.test(lower)) accessories.push('batterie');
if (/chargeur/i.test(lower)) accessories.push('chargeur');
result.accessories = [...new Set(accessories)];
result.usage_notes = text;
return [{ json: { ...$json, message_facts: result }, binary: $input.first()?.binary }];

const root = $json || {};
const tempDriveRootId = root.temp_drive_root_id || root.temp_root_folder_id || root.context?.default_drive_root_id || root.default_drive_root_id || null;
const tempFolderId = root.temp_drive_folder_id || root.id || null;
return [{ json: {
  ...root,
  temp_drive_root_id: tempDriveRootId,
  temp_drive_folder_id: tempFolderId,
  temp_drive_folder_name: root.temp_drive_folder_name || root.name || root.ingestion_id || null,
  temp_drive_folder_path: root.temp_drive_folder_path || (root.ingestion_id ? `SIGA_TEMP/${String(root.ingestion_id)}` : null),
  temp_drive_folder_web_view_link: root.temp_drive_folder_web_view_link || root.webViewLink || null,
}, binary: $input.first()?.binary }];

const root = $json;
const images = Array.isArray(root.images) ? root.images : [];
const inputBinary = $input.first()?.binary || {};
return images.map((img, idx) => {
  const hasBinaryKey = !!img.binary_key;
  const hasBase64 = !!img.content_base64;
  const imageIndex = Number(img.index || idx + 1);
  const imageUid = String(root.ingestion_id || 'SIGA') + '-IMG' + String(imageIndex).padStart(3, '0');
  const base = {
    ...root,
    image_index: imageIndex,
    image_uid: imageUid,
    current_image: img,
    original_filename: img.filename || ('image_' + imageIndex + '.jpg'),
    mime_type: img.mime_type || 'image/jpeg'
  };
  if (!hasBinaryKey && !hasBase64) {
    return {
      json: {
        ...base,
        processing_status: 'image_error',
        image_error: { code: 'missing_content_base64', message: 'content_base64 is required for OCR and staging in this workflow version' }
      }
    };
  }
  const bk = img.binary_key;
  const itemBinary = bk && inputBinary[bk] ? { [bk]: inputBinary[bk] } : (Object.keys(inputBinary).length > 0 ? inputBinary : undefined);
  return { json: { ...base, processing_status: 'ready_for_ocr_and_staging', image_error: null }, binary: itemBinary };
});

const _msgText = $input.all()[0]?.json?.message?.text || '';
const _OCR_BASE = `Analyse cette photo d'outil ou machine d'atelier. Réponds UNIQUEMENT en JSON strict selon ce schéma exact: {"image_role":"overview|nameplate|detail|unknown","contains_nameplate":true,"detected_object_type":"","brand":"","model":"","serial_number":null,"nameplate_text":"","technical_specs":{},"condition_notes":[],"equipment_count_estimate":1,"readability":0.0,"confidence":0.0,"is_primary_equipment_candidate":false,"primary_equipment_confidence":0.0,"is_accessory_or_consumable":false,"accessory_type":"","secondary_objects":[],"consumable_state":"new|used|very_used|unknown","item_condition":"","item_role":"primary|accessory|consumable|associated_item|packaging|unknown","packaging_detected":false,"is_packaged_item":false,"missing_visual_information":[]}. Pour secondary_objects, utilise une liste d'objets de forme {"label":"","object_type":"","item_role":"accessory|consumable|associated_item|packaging|unknown","consumable_state":"new|used|very_used|unknown","item_condition":"","packaging_detected":false,"is_packaged_item":false,"brand":"","model":"","confidence":0.0,"evidence":[]}. Règles: 1) image_role=overview pour vue globale de l'équipement, nameplate pour plaque signalétique / étiquette technique, detail pour détail/état/usure, unknown sinon. 2) brand/model/serial/specs prioritairement si lisibles. 3) condition_notes = liste courte de constats visuels factuels. 4) confidence, readability et primary_equipment_confidence entre 0 et 1. 5) Si l'image montre surtout un emballage, un disque, une lame, une boîte, un consommable ou un accessoire isolé, renseigne is_accessory_or_consumable=true, accessory_type si possible, et n'en fais pas l'équipement principal. 6) Si l'image montre clairement la machine / l'outil principal, renseigne is_primary_equipment_candidate=true. 7) Détecte aussi les objets secondaires visibles autour de l'équipement principal: disque, lame, batterie, chargeur, emballage, boîte, lot de consommables, etc. Remplis secondary_objects même si l'objet principal reste la machine. 8) Pour les consommables de coupe (disque/lame), qualifie au mieux consumable_state: new si neuf / emballé / très peu utilisé, used si usure visible modérée, very_used si très forte usure, inconnu sinon. 9) packaging_detected=true si emballage/boîte/sachet visible; is_packaged_item=true si l'objet semble encore dans son emballage ou présenté comme produit emballé. 10) item_role doit refléter la fonction métier de l'objet observé, sans jamais promouvoir un objet secondaire comme équipement principal. 11) Si le modèle d'un disque/accessoire n'est pas lisible, ne l'invente pas. 12) Pas de markdown, pas d'explication, JSON strict seulement.`;
const _ocrPrompt = _msgText ? `[Contexte de l'opérateur: ${_msgText}]\n\n${_OCR_BASE}` : _OCR_BASE;

// Pre-fetch binary data from source nodes at top level ($(n) must not be called inside nested functions)
let _wb_bin = {};
try { _wb_bin = $('Webhook In').first()?.binary || {}; } catch(e) {}
let _tg_bin = {};
try { _tg_bin = $('Telegram Trigger').first()?.binary || {}; } catch(e) {}
let _ni_bin = {};
try { _ni_bin = $('Normalize Input').first()?.binary || {}; } catch(e) {}

return $input.all().map(item => {
  const j = item.json || {};
  const img = j.current_image || {};
  const binaryKey = img.binary_key || null;

  // 1. Binary directement dans l'item courant sous binary_key (cas filesystem-v2)
  if (binaryKey && item.binary?.[binaryKey]) {
    const binRef = { ...item.binary[binaryKey] };
    if (!binRef.fileName) binRef.fileName = img.filename || ('image_' + (j.image_index || 1) + '.jpg');
    if (!binRef.mimeType) binRef.mimeType = img.mime_type || 'image/jpeg';
    return { json: { ...j, _binary_ready: true, ocr_context_prompt: _ocrPrompt, _binary_source: 'item.' + binaryKey }, binary: { data: binRef }, pairedItem: item.pairedItem ?? 0 };
  }

  // 2. Binary sous clé générique 'data'
  if (item.binary?.data) {
    return { json: { ...j, _binary_ready: true, ocr_context_prompt: _ocrPrompt, _binary_source: 'current_item.data' }, binary: { data: item.binary.data }, pairedItem: item.pairedItem ?? 0 };
  }

  // 3. Chercher dans les noeuds source (binaries pré-fetchées au top level)
  let resolved = null;
  if (binaryKey) {
    const sources = [
      { bin: _wb_bin, name: 'Webhook In' },
      { bin: _tg_bin, name: 'Telegram Trigger' },
      { bin: _ni_bin, name: 'Normalize Input' },
    ];
    for (const { bin, name } of sources) {
      if (!resolved && binaryKey && bin[binaryKey]) resolved = { ref: bin[binaryKey], source: name + '.' + binaryKey };
    }
    for (const { bin, name } of sources) {
      if (!resolved && bin.data) resolved = { ref: bin.data, source: name + '.data' };
    }
  }

  if (resolved?.ref) {
    const binRef = { ...resolved.ref };
    if (!binRef.fileName) binRef.fileName = img.filename || ('image_' + (j.image_index || 1) + '.jpg');
    if (!binRef.mimeType) binRef.mimeType = img.mime_type || 'image/jpeg';
    return { json: { ...j, _binary_ready: true, ocr_context_prompt: _ocrPrompt, _binary_source: resolved.source }, binary: { data: binRef }, pairedItem: item.pairedItem ?? 0 };
  }

  if (!img.content_base64 || img.content_base64 === 'filesystem-v2') {
    return { json: { ...j, _binary_ready: false, ocr_context_prompt: _ocrPrompt } };
  }

  return {
    json: { ...j, _binary_ready: true, ocr_context_prompt: _ocrPrompt, _binary_source: 'content_base64' },
    binary: {
      data: {
        data: img.content_base64,
        mimeType: img.mime_type || 'image/jpeg',
        fileName: img.filename || ('image_' + (j.image_index || 1) + '.jpg')
      }
    },
    pairedItem: item.pairedItem ?? 0
  };
});

